import{_ as t,o as a,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",m=JSON.parse('{"title":"Reset a Forgotten Password","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/forgot-password.md","filePath":"getting-started/forgot-password.md"}'),n={name:"getting-started/forgot-password.md"};function i(l,e,h,d,u,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="reset-a-forgotten-password" tabindex="-1">Reset a Forgotten Password <a class="header-anchor" href="#reset-a-forgotten-password" aria-label="Permalink to &quot;Reset a Forgotten Password&quot;">​</a></h1><p>If you can&#39;t remember your password, you can ask for it to be reset. <strong>This app does not send an automatic reset link</strong> — instead, an admin reviews and approves your request. That keeps accounts secure in a shared kingdom.</p><h2 id="requesting-a-reset" tabindex="-1">Requesting a reset <a class="header-anchor" href="#requesting-a-reset" aria-label="Permalink to &quot;Requesting a reset&quot;">​</a></h2><p><img src="'+s+'" alt="Forgot password form"></p><ol><li>On the login screen, choose <strong>Forgot password</strong>.</li><li>Enter the details asked for (such as your username or email).</li><li>Submit the request.</li></ol><p>Your request now goes to your kingdom&#39;s admins. You&#39;ll keep using your old password until the reset is approved (or you&#39;ll be given a new temporary one).</p><h2 id="what-happens-next" tabindex="-1">What happens next <a class="header-anchor" href="#what-happens-next" aria-label="Permalink to &quot;What happens next&quot;">​</a></h2><ul><li>An admin (Supreme Admin or King) sees your request in their <strong>Password Requests</strong> list.</li><li>They either <strong>approve</strong> it — after which you&#39;ll be able to sign in with a new or temporary password — or <strong>reject</strong> it if something doesn&#39;t look right.</li><li>Once approved, log in and, if prompted, set a new password of your own on the <a href="./your-profile.html">profile page</a>.</li></ul><h2 id="why-there-s-no-instant-email-link" tabindex="-1">Why there&#39;s no instant email link <a class="header-anchor" href="#why-there-s-no-instant-email-link" aria-label="Permalink to &quot;Why there&#39;s no instant email link&quot;">​</a></h2><p>Because kingdoms share administration, password resets are handled by a trusted person rather than automatically. This prevents someone from resetting an account that isn&#39;t theirs. The trade‑off is that a reset takes a little longer — it depends on an admin being available.</p><h2 id="if-you-re-in-a-hurry" tabindex="-1">If you&#39;re in a hurry <a class="header-anchor" href="#if-you-re-in-a-hurry" aria-label="Permalink to &quot;If you&#39;re in a hurry&quot;">​</a></h2><ul><li>Contact your Alliance Leader or King directly and let them know you&#39;ve filed a reset request.</li><li>Double‑check you&#39;re using the right username first — sometimes it&#39;s not the password that&#39;s the problem.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./logging-in.html">Log In &amp; Out</a> — including the &quot;too many attempts&quot; cooldown.</li><li><a href="./your-profile.html">Edit Your Profile &amp; Password</a> — changing your password once you&#39;re in.</li></ul>',14)])])}const c=t(n,[["render",i]]);export{m as __pageData,c as default};
